    "severity": "critical",
    "description": "The isFeatureAllowedForScope function does not handle the optional 'scope' field. When config.scope is undefined, calling .includes() throws a runtime error. According to the documentation (lines 70-71), 'Features without a scope field are allowed for all scopes', but the code doesn't implement this logic.",
    "fix_patch": "--- a/packages/features/feature-opt-in/config.ts
+++ b/packages/features/feature-opt-in/config.ts
@@ -73,5 +73,5 @@ export function getOptInFeaturesForScope(scope: OptInFeatureScope): OptInFeatureC
 export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
   const config = getOptInFeatureConfig(slug);
   if (!config) return false;
-  return config.scope.includes(scope);
+  return !config.scope || config.scope.includes(scope);
 }
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 161,
    "severity": "high",
    "description": "The policy is hardcoded to 'permissive' for all features instead of being retrieved from the feature configuration. This violates the compliance principle of using configuration instead of hardcoded values. The policy should come from getOptInFeatureConfig(featureId) which is already imported and available.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -158,7 +158,7 @@ export class FeatureOptInService implements IFeatureOptInService {
       userAutoOptIn
     );

-    const policy: OptInFeaturePolicy = "permissive";
+    const policy = getOptInFeatureConfig(featureId)?.policy ?? "permissive";

     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
       globalEnabled,
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 205,
    "severity": "high",
    "description": "The filter condition at line 205 contradicts the function documentation (lines 187-188). The comment states the function 'Only returns features that are in the allowlist, globally enabled, and scoped to "user"', but the filter checks for !state.globalEnabled (features that are NOT globally enabled). This is inconsistent with listFeaturesForTeam (line 240) which filters for globalEnabled. For opt-in features shown to users, we should only display features that are globally available (enabled).",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -202,6 +202,6 @@ export class FeatureOptInService implements IFeatureOptInService {
       featureIds,
     });

-    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => !state.globalEnabled);
+    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
   }

   /**
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 95,
    "severity": "high",
    "description": "The setUserState mutation is missing slug validation against the allowlist before processing. The setTeamState (line 117) and setOrganizationState (line 146) endpoints both validate using isOptInFeature, but setUserState does not. This is a compliance violation (missing input validation) and a type safety issue - the code passes a 'string' slug directly to the service which expects a 'FeatureId' type. Without the validation guard, TypeScript's type narrowing doesn't apply.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -93,6 +93,12 @@ export const featureOptInRouter = router({
       })
     )
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
+
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

